// Agrupa los comprobantes por vendedora y prepara mensajes
const items = $input.first().json.items || [];

const NUMEROS_WA = {
  betty: '573506974711',
  ney:   '573016639430',
  wendy: '573118287892',
  paola: '573026027865',
};

// Agrupar por vendedora
const porVendedora = {};
const messageIds = [];
for (const c of items) {
  if (c.messageId) messageIds.push(c.messageId);
  const ven = String(c.vendedora || 'desconocida').toLowerCase();
  if (!porVendedora[ven]) porVendedora[ven] = { ventasNuevas: [], abonos: [], otros: [] };
  if (c.clasificacion === 'venta-nueva') porVendedora[ven].ventasNuevas.push(c);
  else if (c.clasificacion === 'abono') porVendedora[ven].abonos.push(c);
  else porVendedora[ven].otros.push(c);
}

function fmtMonto(m) { if (!m) return '?'; return '$' + Number(m).toLocaleString('es-CO'); }

// Mensajes para cada vendedora
const vendedorasMensajes = [];
for (const [ven, data] of Object.entries(porVendedora)) {
  const numero = NUMEROS_WA[ven];
  if (!numero) continue;
  const total = data.ventasNuevas.length + data.abonos.length + data.otros.length;
  if (!total) continue;
  let txt = `Hola ${ven.charAt(0).toUpperCase() + ven.slice(1)} 👋\n\n`;
  txt += `Detectamos ${total} comprobante${total > 1 ? 's' : ''} hoy en chats que NO marcaste con 💰:\n`;
  if (data.ventasNuevas.length) {
    txt += `\n🆕 *Posibles ventas nuevas:*\n`;
    data.ventasNuevas.forEach(c => { txt += `• ${c.cliente || c.telefono} — ${c.banco || '?'} ${fmtMonto(c.monto)}\n`; });
  }
  if (data.abonos.length) {
    txt += `\n💵 *Pagos a pedidos en proceso (informativo):*\n`;
    data.abonos.forEach(c => { txt += `• ${c.cliente || c.telefono} — pedido "${c.pedidoMatch?.equipo || '?'}" — ${c.banco || '?'} ${fmtMonto(c.monto)}\n`; });
  }
  if (data.otros.length) {
    txt += `\n👀 *Cliente recurrente:*\n`;
    data.otros.forEach(c => { txt += `• ${c.cliente || c.telefono} — ${c.banco || '?'} ${fmtMonto(c.monto)}\n`; });
  }
  txt += `\nSi alguna es venta confirmada, mandale el sticker 💰 al chat.`;
  vendedorasMensajes.push({ vendedora: ven, numero, mensaje: txt });
}

// Resumen consolidado para Duvan
let resumenDuvan = `📊 *Resumen del día — Comprobantes detectados*\n\n`;
resumenDuvan += `Total sin marcar: ${items.length}\n\n`;
for (const [ven, data] of Object.entries(porVendedora)) {
  const total = data.ventasNuevas.length + data.abonos.length + data.otros.length;
  resumenDuvan += `*${ven.charAt(0).toUpperCase() + ven.slice(1)}:* ${total}`;
  if (data.ventasNuevas.length) resumenDuvan += ` (🆕 ${data.ventasNuevas.length} nuevas`;
  if (data.abonos.length) resumenDuvan += `${data.ventasNuevas.length ? ', ' : ' ('}💵 ${data.abonos.length} abonos`;
  if (data.ventasNuevas.length || data.abonos.length) resumenDuvan += ')';
  resumenDuvan += `\n`;
}
if (!items.length) resumenDuvan = `✅ Hoy todas las vendedoras marcaron sus ventas.`;

return [{
  json: {
    hay: items.length > 0,
    total: items.length,
    vendedorasMensajes,
    resumenDuvan,
    messageIds,
  }
}];
